// ============================================================
// EXTRACT & NORMALIZE JIRA TICKET DATA
// ============================================================
const body = $input.item.json.body || $input.item.json;
const issue = body.issue || {};
const fields = issue.fields || {};

const key = issue.key || '';
const projectKey = (fields.project && fields.project.key) || key.split('-')[0];

// Only process REQ project
if (projectKey !== 'REQ') {
  return [{ json: { skip: true, reason: 'Not a REQ ticket', key } }];
}

const summary = fields.summary || '';
const issueType = (fields.issuetype && fields.issuetype.name) || '';
const status = (fields.status && fields.status.name) || 'BACKLOG';
const assignee = (fields.assignee && fields.assignee.displayName) || '';
const createdAt = fields.created || new Date().toISOString();
const updatedAt = fields.updated || new Date().toISOString();
const jiraUrl = `https://arduasolutions.atlassian.net/browse/${key}`;

// Normalize issue type
let tipo = 'REQ';
if (issueType === 'Task' || issueType === 'TASK') tipo = 'TASK';

// Determine responsable based on status
const responsabilidadProducto = ['BACKLOG', 'IN ANALYSIS', 'In Progress', 'Blocked'];
const responsabilidadIT = ['SENT TO DEV', 'Ready for Dev', 'In Development'];
const responsabilidadNinguno = ['Done', 'DEPRECATED'];

let responsable = 'Producto';
if (responsabilidadIT.includes(status)) responsable = 'IT';
if (responsabilidadNinguno.includes(status)) responsable = 'Ninguno';

// Format date as YYYY-MM-DD
const formatDate = (iso) => iso ? iso.split('T')[0] : null;
const today = formatDate(new Date().toISOString());

return [{
  json: {
    skip: false,
    key,
    summary,
    tipo,
    status,
    responsable,
    assignee,
    createdAt: formatDate(createdAt),
    updatedAt: formatDate(updatedAt),
    jiraUrl,
    today
  }
}];

// ============================================================
// BUILD NOTION PAGE PROPERTIES FOR SLA — Tickets PRODUCTS
// Data Source ID: 9d7ea3de-0af8-4d78-9b56-0dfd5643a422
// ============================================================
const d = $input.item.json;

// Map status to the correct 'Fecha entrada [estado]' field
const statusToFechaField = {
  'BACKLOG':         'date:Fecha entrada BACKLOG:start',
  'IN ANALYSIS':     'date:Fecha entrada IN ANALYSIS:start',
  'In Progress':     'date:Fecha entrada In Progress:start',
  'Blocked':         'date:Fecha entrada Blocked:start',
  'SENT TO DEV':     'date:Fecha entrada SENT TO DEV:start',
  'Ready for Dev':   'date:Fecha entrada Ready for Dev:start',
  'In Development':  'date:Fecha entrada In Development:start',
  'Done':            'date:Fecha entrada Done:start',
  'DEPRECATED':      'date:Fecha entrada DEPRECATED:start'
};

const fechaField = statusToFechaField[d.status];

const properties = {
  // Base fields
  'Ticket Key':           d.key,
  'Summary':              d.summary,
  'Tipo':                 d.tipo,
  'Estado Actual':        d.status,
  'Responsable':          d.responsable,
  'IT es responsable':    d.responsable === 'IT' ? '__YES__' : '__NO__',
  'Assignee':             d.assignee,
  'date:Fecha Creación:start':       d.createdAt,
  'date:Fecha Creación:is_datetime': 0,
  'date:Última Actualización:start': d.updatedAt,
  'date:Última Actualización:is_datetime': 0,
  'Días en Estado Actual': 0,
  'userDefined:URL Jira':  d.jiraUrl
};

// Set fecha entrada for current status
if (fechaField) {
  properties[fechaField] = d.today;
  properties[fechaField.replace(':start', ':is_datetime')] = 0;
}

return [{ json: { properties, key: d.key } }];
